import {useEffect,useState} from "react";
import axios from "axios";
import {MapContainer,TileLayer,Popup,Circle,useMap} from "react-leaflet";
import "leaflet/dist/leaflet.css";

function ChangeMapView({coords}){
  const map = useMap();

  useEffect(()=>{
    if(coords){
      map.setView(coords,15);
    }
  },[coords,map]);

  return null;
}

export default function PoliceDashboard(){

  const [alerts,setAlerts]=useState([]);
  const [loading,setLoading]=useState(true);
  const [error,setError]=useState("");
  const [selectedLocation,setSelectedLocation]=useState(null);
  const [pulse,setPulse]=useState(80);

  const [showModal,setShowModal]=useState(false);
  const [selectedAlertId,setSelectedAlertId]=useState(null);
  const [proofImage,setProofImage]=useState(null);

  const loadAlerts=()=>{
    axios.get("http://127.0.0.1:8000/api/admin-alerts/")
      .then(res=>{
        setAlerts(res.data);
        setLoading(false);
      })
      .catch(()=>{
        setError("Failed to load alerts");
        setLoading(false);
      });
  }

  useEffect(()=>{ loadAlerts(); },[]);
  useEffect(()=>{
    const interval=setInterval(loadAlerts,10000);
    return ()=>clearInterval(interval);
  },[]);
  useEffect(()=>{
    const interval=setInterval(()=>setPulse(p=>p===80?130:80),700);
    return ()=>clearInterval(interval);
  },[]);

  const openResolveModal=(id)=>{
    setSelectedAlertId(id);
    setShowModal(true);
  }

  const submitResolve=()=>{
    if(!proofImage) return alert("Upload proof");

    navigator.geolocation.getCurrentPosition(pos=>{
      const formData=new FormData();
      formData.append("proof_image",proofImage);
      formData.append("latitude",pos.coords.latitude);
      formData.append("longitude",pos.coords.longitude);

      axios.post(`http://127.0.0.1:8000/api/resolve-api/${selectedAlertId}/`,formData)
      .then(()=>{
        alert("Resolved ✅");
        setShowModal(false);
        setProofImage(null);
        loadAlerts();
      })
      .catch(()=>alert("Verification failed ❌"));
    });
  }

  const active=alerts.filter(a=>a.status!=="resolved");
  const resolved=alerts.filter(a=>a.status==="resolved");

  if(loading) return <div>Loading...</div>;
  if(error) return <div>{error}</div>;

  return(
    <div style={{padding:30,color:"white"}}>

      <h1>🚓 Police Dashboard</h1>

      <MapContainer center={[17.38,78.48]} zoom={11} style={{height:350}}>
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>
        <ChangeMapView coords={selectedLocation}/>

        {active.map(a=>(
          <Circle key={a.id} center={[a.latitude,a.longitude]} radius={pulse}>
            <Popup>{a.message}</Popup>
          </Circle>
        ))}
      </MapContainer>

      <h2>Active Alerts</h2>
      <Table alerts={active} resolveAlert={openResolveModal} setSelectedLocation={setSelectedLocation}/>

      <h2>Resolved</h2>
      <Table alerts={resolved} setSelectedLocation={setSelectedLocation}/>

      {showModal && (
        <Modal submitResolve={submitResolve} setProofImage={setProofImage} close={()=>setShowModal(false)}/>
      )}
    </div>
  )
}
